class TestCsvParsing:
    """Tests focused on CSV structure and header validation."""

    def test_empty_csv_returns_error(self, repo):
        result = import_employees_from_csv("", repo)
        assert result.total_committed == 0
        assert 0 in result.errors

    def test_headers_only_no_data_rows_commits_nothing(self, repo):
        csv_content = make_csv()   # no data rows
        result = import_employees_from_csv(csv_content, repo)
        assert result.total_committed == 0
        assert result.total_errors == 0
        repo.save.assert_not_called()

    def test_missing_required_header_returns_header_error(self, repo):
        # omit 'email' column entirely
        headers = [h for h in REQUIRED_HEADERS if h != "email"]
        row = {k: v for k, v in VALID_ROW_1.items() if k != "email"}
        csv_content = make_csv(row, headers=headers)
        result = import_employees_from_csv(csv_content, repo)
        assert result.total_committed == 0
        assert 0 in result.errors
        assert any("email" in msg for msg in result.errors[0])

    def test_multiple_missing_headers_all_reported(self, repo):
        headers = ["first_name", "last_name"]   # many missing
        csv_content = make_csv({"first_name": "X", "last_name": "Y"}, headers=headers)
        result = import_employees_from_csv(csv_content, repo)
        assert 0 in result.errors
        error_text = " ".join(result.errors[0])
        for missing in ("email", "department", "salary", "job_title"):
            assert missing in error_text

    def test_extra_columns_are_ignored(self, repo):
        headers = list(REQUIRED_HEADERS) + ["extra_column"]
        row = {**VALID_ROW_1, "extra_column": "ignored"}
        csv_content = make_csv(row, headers=headers)
        result = import_employees_from_csv(csv_content, repo)
        assert result.total_committed == 1
        assert result.total_errors == 0

    def test_whitespace_in_header_names_tolerated(self, repo):
        """Headers with surrounding spaces should still be recognised."""
        buf = io.StringIO()
        # Manually write a CSV with padded headers
        padded = " , ".join(f" {h} " for h in REQUIRED_HEADERS)
        buf.write(padded + "\n")
        buf.write(",".join(VALID_ROW_1[h] for h in REQUIRED_HEADERS) + "\n")
        # This test documents expected tolerance; adjust if impl strips headers.
        # Here we just ensure no crash and the result is deterministic.
        result = import_employees_from_csv(buf.getvalue(), repo)
        assert isinstance(result, ImportResult)


