        bad_row = {**VALID_ROW_1, "email": "broken"}
        csv_content = make_csv(bad_row, VALID_ROW_2, VALID_ROW_3)
        result = import_employees_from_csv(csv_content, repo)
        assert result.total_committed == 2
        assert 2 in result.errors

