        bad1 = {**VALID_ROW_1, "email": "bad"}
        bad2 = {**VALID_ROW_2, "salary": "0"}
        bad3 = {**VALID_ROW_3, "department": "Nope"}
        csv_content = make_csv(bad1, bad2, bad3)
        result = import_employees_from_csv(csv_content, repo)
        assert result.total_committed == 0
        assert result.total_errors == 3
        repo.save.assert_not_called()

    def test_large_import_partial_commit(self, repo):
        """50 valid rows + 10 invalid rows scattered throughout."""
        rows = []
        expected_invalid = set()
        for i in range(60):
            if i % 6 == 0:            # every 6th row is invalid
                rows.append({**VALID_ROW_1, "email": "bad", "first_name": f"Bad{i}"})
                expected_invalid.add(i + 2)   # +2 because header is row 1
            else:
                rows.append({
                    **VALID_ROW_1,
                    "email": f"user{i}@example.com",
                    "first_name": f"User{i}",
                })
        csv_content = make_csv(*rows)
        result = import_employees_from_csv(csv_content, repo)
        assert result.total_committed == 50
        assert result.total_errors == 10


